import { Client, Environment } from "square";

const accessToken = process.env.SQUARE_ACCESS_TOKEN;
const environment = process.env.SQUARE_ENVIRONMENT ?? "sandbox";

if (!accessToken) {
  throw new Error("Missing SQUARE_ACCESS_TOKEN in environment.");
}

export const squareClient = new Client({
  accessToken,
  environment:
    environment === "production" ? Environment.Production : Environment.Sandbox,
});

export function getSquareLocationId(): string {
  const id = process.env.SQUARE_LOCATION_ID;
  if (!id) {
    throw new Error("Missing SQUARE_LOCATION_ID in environment.");
  }
  return id;
}

import { Router } from "express";
import { randomUUID } from "node:crypto";
import {
  getSquareLocationId,
  squareClient,
} from "../services/squareClient.js";

export const squareCheckoutRouter = Router();

// POST /api/checkout — create a Square hosted checkout link for a list of
// line items. Replace the request body shape with your real payload before
// going live.
squareCheckoutRouter.post("/", async (req, res, next) => {
  try {
    const { lineItems } = req.body as {
      lineItems?: { name: string; quantity: string; amount: number }[];
    };

    if (!lineItems || lineItems.length === 0) {
      res.status(400).json({ error: { message: "lineItems is required." } });
      return;
    }

    const response = await squareClient.checkoutApi.createPaymentLink({
      idempotencyKey: randomUUID(),
      order: {
        locationId: getSquareLocationId(),
        lineItems: lineItems.map((item) => ({
          name: item.name,
          quantity: item.quantity,
          basePriceMoney: {
            amount: BigInt(item.amount),
            currency: "USD",
          },
        })),
      },
    });

    const link = response.result.paymentLink;
    if (!link?.url) {
      res.status(502).json({
        error: { message: "Square did not return a checkout URL." },
      });
      return;
    }

    res.json({ data: { url: link.url, id: link.id } });
  } catch (err) {
    next(err);
  }
});
